function withTempDir<T>(fn: (dir: string) => T): T {
	const dir = mkdtempSync(join(tmpdir(), "pi-subagent-"));
	try {
		return fn(dir);
	} finally {
		rmSync(dir, { recursive: true });
	}
}

test("escapeShellArg wraps in single quotes", () => {
	withTempDir((_tmp) => {
		strictEqual(escapeShellArg("hello"), "'hello'");
		strictEqual(escapeShellArg("it's"), "'it'\\''s'");
		strictEqual(escapeShellArg(""), "''");
	});
});

test("buildShellCommand contains expected parts", () => {
	withTempDir((_tmp) => {
		const cmd = buildShellCommand("echo hi", "/tmp/out.txt");
		ok(cmd.includes("--no-interactive"));
		ok(cmd.includes("-p"));
		ok(cmd.includes("'echo hi'"));
		ok(cmd.includes("'/tmp/out.txt'"));
		ok(cmd.includes("tee"));
		ok(cmd.includes("=== EXIT:$? ==="));
	});
});

test("waitForSubagent resolves when sentinel appears", async () => {
	await withTempDir(async (tmp) => {
		const outputFile = join(tmp, "output.txt");
		writeFileSync(outputFile, "hello world\n=== EXIT:42 ===\n");
		const result = await waitForSubagent("fake-id", undefined, undefined, outputFile);
		strictEqual(result.output, "hello world");
		strictEqual(result.exitCode, 42);
	});
});

test("waitForSubagent streams partial output via onUpdate", async () => {
	await withTempDir(async (tmp) => {
		const outputFile = join(tmp, "output.txt");
		writeFileSync(outputFile, "partial\n");

		const updates: string[] = [];
		const ac = new AbortController();

		// Append sentinel after a short delay
		const timer = setTimeout(() => {
			writeFileSync(outputFile, "partial\n=== EXIT:0 ===\n");
		}, 300);

		try {
			const result = await waitForSubagent(
				"fake-id",
				ac.signal,
				(out) => updates.push(out),
				outputFile,
			);
			strictEqual(result.output, "partial");
			strictEqual(result.exitCode, 0);
			ok(updates.length > 0);
			strictEqual(updates[0], "partial\n");
		} finally {
			clearTimeout(timer);
		}
	});
});

test("waitForSubagent throws on abort", async () => {
	await withTempDir(async (tmp) => {
		const outputFile = join(tmp, "output.txt");
		writeFileSync(outputFile, "no sentinel\n");
		const ac = new AbortController();
		ac.abort();
		await strictEqual(
			await waitForSubagent("fake-id", ac.signal, undefined, outputFile).catch((e) => e.message),
			"Aborted",
		);
	});
});

